import { config as defaultConfig, type GameConfig } from "../../config/index.js";
import {
  AmbientDirectorProvider,
  type AmbientDirectorProviderOptions,
} from "./ambient.js";
import {
  MockDirectorProvider,
  type MockDirectorProviderOptions,
} from "./mock.js";
import {
  type DirectorProvider,
  type JudgeResult,
  type ProviderResult,
  failure,
} from "./types.js";

export * from "./ambient.js";
export * from "./mock.js";
export * from "./types.js";

export type CreateDirectorProviderOptions = {
  readonly config?: GameConfig;
  readonly mock?: MockDirectorProviderOptions;
  readonly ambient?: AmbientDirectorProviderOptions;
};

export const createDirectorProvider = (
  options: CreateDirectorProviderOptions = {},
): DirectorProvider => {
  const config = options.config ?? defaultConfig;

  switch (config.director.provider) {
    case "mock":
      return new MockDirectorProvider(options.mock);
    case "ambient":
      return new AmbientDirectorProvider(options.ambient);
    case "api-future":
      return new DeferredApiFutureDirectorProvider();
  }
};

class DeferredApiFutureDirectorProvider implements DirectorProvider {
  async generateManifest(): Promise<ProviderResult> {
    return failure(
      "process_error",
      "api-future provider is deferred until an API key exists",
      { latencyMs: 0, tokens: null },
    );
  }

  async judge(): Promise<JudgeResult> {
    return failure(
      "process_error",
      "api-future judge provider is deferred until an API key exists",
      { latencyMs: 0, tokens: null },
    );
  }
}

import { validShallowsManifestFixture } from "../../schemas/fixtures/manifest.js";
import type { FloorManifest } from "../../schemas/manifest.js";
import {
  type DirectorProvider,
  type GenerateManifestOptions,
  type JudgeOptions,
  type JudgeResult,
  type JudgeVerdict,
  type ProviderFailureCode,
  type ProviderResult,
  type ProviderTokenUsage,
  type ProviderUsage,
  failure,
} from "./types.js";

export type MockDirectorProviderOptions = {
  readonly manifest?: FloorManifest;
  readonly raw?: string;
  readonly failureMode?: ProviderFailureCode | null;
  readonly judgeVerdict?: JudgeVerdict;
  readonly judgeRaw?: string;
  readonly judgeFailureMode?: ProviderFailureCode | null;
  readonly latencyMs?: number;
  readonly tokens?: ProviderTokenUsage | null;
};

const DEFAULT_JUDGE_VERDICT: JudgeVerdict = {
  verdict: "pass",
  reason: "mock verdict",
  score: 1,
};

export class MockDirectorProvider implements DirectorProvider {
  private readonly manifest: FloorManifest;
  private readonly raw: string;
  private readonly failureMode: ProviderFailureCode | null;
  private readonly judgeVerdict: JudgeVerdict;
  private readonly judgeRaw: string;
  private readonly judgeFailureMode: ProviderFailureCode | null;
  private readonly usage: ProviderUsage;

  constructor(options: MockDirectorProviderOptions = {}) {
    this.manifest = options.manifest ?? validShallowsManifestFixture;
    this.raw = options.raw ?? JSON.stringify(this.manifest);
    this.failureMode = options.failureMode ?? null;
    this.judgeVerdict = options.judgeVerdict ?? DEFAULT_JUDGE_VERDICT;
    this.judgeRaw = options.judgeRaw ?? JSON.stringify(this.judgeVerdict);
    this.judgeFailureMode = options.judgeFailureMode ?? null;
    this.usage = {
      latencyMs: options.latencyMs ?? 0,
      tokens: options.tokens ?? null,
    };
  }

  async generateManifest(
    prompt: string,
    options: GenerateManifestOptions = {},
  ): Promise<ProviderResult> {
    void prompt;
    void options;

    if (this.failureMode !== null) {
      return failure(
        this.failureMode,
        `mock ${this.failureMode}`,
        this.usage,
        this.raw,
      );
    }

    return {
      ok: true,
      raw: this.raw,
      manifest: this.manifest,
      usage: this.usage,
    };
  }

  async judge(prompt: string, options: JudgeOptions = {}): Promise<JudgeResult> {
    void prompt;
    void options;

    if (this.judgeFailureMode !== null) {
      return failure(
        this.judgeFailureMode,
        `mock judge ${this.judgeFailureMode}`,
        this.usage,
        this.judgeRaw,
      );
    }

    return {
      ok: true,
      raw: this.judgeRaw,
      verdict: this.judgeVerdict,
      usage: this.usage,
    };
  }
}

export const createMockDirectorProvider = (
  options: MockDirectorProviderOptions = {},
): MockDirectorProvider => new MockDirectorProvider(options);

import {
  nodeArtifactFsAdapter,
  trimTrailingSlash,
  type ArtifactFsAdapter,
} from "./fs.js";
import type {
  FloorIndexEntry,
  GenerationRecord,
  RunGenerationIndex,
  RunGenerationSummary,
} from "./types.js";

export type ArtifactReadOptions = {
  readonly rootDir?: string;
  readonly fs?: ArtifactFsAdapter;
};

const INDEX_FILE = "index.json";

const resolveReadContext = (options: ArtifactReadOptions = {}) => ({
  rootDir: trimTrailingSlash(options.rootDir ?? "runs"),
  fs: options.fs ?? nodeArtifactFsAdapter,
});

const loadRunIndexFile = (
  fs: ArtifactFsAdapter,
  rootDir: string,
  runId: string,
): RunGenerationIndex => {
  const indexPath = `${rootDir}/${runId}/${INDEX_FILE}`;
  if (!fs.fileExists(indexPath)) {
    throw new Error(`generation index not found for run: ${runId}`);
  }

  return JSON.parse(fs.readFile(indexPath)) as RunGenerationIndex;
};

export const listRuns = (
  options: ArtifactReadOptions = {},
): readonly RunGenerationSummary[] => {
  const { rootDir, fs } = resolveReadContext(options);
  if (!fs.isDirectory(rootDir)) {
    return [];
  }

  const summaries: RunGenerationSummary[] = [];

  for (const runId of fs.listEntries(rootDir)) {
    const indexPath = `${rootDir}/${runId}/${INDEX_FILE}`;
    if (!fs.fileExists(indexPath)) {
      continue;
    }

    const index = JSON.parse(fs.readFile(indexPath)) as RunGenerationIndex;
    if (index.recordType !== "generation-index") {
      continue;
    }

    summaries.push({
      runId: index.runId,
      stamp: {
        recordType: "generation-stamp",
        protocolVersion: index.protocolVersion,
        engineVersion: index.engineVersion,
        modelId: index.modelId,
        seed: index.seed,
        createdAt: index.createdAt,
      },
      updatedAt: index.updatedAt,
      floorCount: index.floors.length,
    });
  }

  return summaries.sort((left, right) =>
    right.updatedAt.localeCompare(left.updatedAt),
  );
};

export const listFloors = (
  runId: string,
  options: ArtifactReadOptions = {},
): readonly FloorIndexEntry[] => {
  const { rootDir, fs } = resolveReadContext(options);
  const index = loadRunIndexFile(fs, rootDir, runId);
  return [...index.floors].sort((left, right) => left.depth - right.depth);
};

export const loadGenerationChain = (
  runId: string,
  depth: number,
  options: ArtifactReadOptions = {},
): GenerationRecord => {
  const { rootDir, fs } = resolveReadContext(options);
  const index = loadRunIndexFile(fs, rootDir, runId);
  const floorEntry = index.floors.find((entry) => entry.depth === depth);
  if (floorEntry === undefined) {
    throw new Error(
      `generation record not indexed for run ${runId} floor ${depth}`,
    );
  }

  const recordPath = `${rootDir}/${runId}/${floorEntry.recordPath}`;
  if (!fs.fileExists(recordPath)) {
    throw new Error(`generation record missing at ${recordPath}`);
  }

  return JSON.parse(fs.readFile(recordPath)) as GenerationRecord;
};

export const readRunIndex = (
  runId: string,
  options: ArtifactReadOptions = {},
): RunGenerationIndex => {
  const { rootDir, fs } = resolveReadContext(options);
  return loadRunIndexFile(fs, rootDir, runId);
};

import { config } from "../config/index.js";
import type {
  FloorContent,
  FloorContentProvider,
  HoardFeatureParams,
} from "../engine/run/loop.js";
import {
  FallbackContentValidationError,
  getFallbackFloor,
  loadFallbackContentPack,
  type FallbackContentPack,
  type ResolvedFallbackFloor,
} from "./content-loader.js";

export type FallbackProviderErrorCode =
  | "fallback_content_invalid"
  | "fallback_depth_unavailable";

export class FallbackProviderError extends Error {
  readonly kind = "fallback-provider-error";
  readonly code: FallbackProviderErrorCode;
  readonly depth: number | null;
  readonly file: string | null;
  readonly entityId: string | null;
  readonly source: unknown;

  constructor(
    code: FallbackProviderErrorCode,
    depth: number | null,
    message: string,
    source: unknown,
  ) {
    super(message);
    this.name = "FallbackProviderError";
    this.code = code;
    this.depth = depth;
    this.source = source;

    if (source instanceof FallbackContentValidationError) {
      this.file = source.file;
      this.entityId = source.entityId;
      return;
    }

    this.file = null;
    this.entityId = null;
  }
}

export type FallbackFloorContentProviderOptions = {
  readonly root?: URL;
  readonly hoard?: HoardFeatureParams;
};

const DEFAULT_HOARD: HoardFeatureParams = {
  id: "hoard",
  name: "The Hoard",
  hint: { distance: "far_from_entrance" },
};

export class FallbackFloorContentProvider implements FloorContentProvider {
  readonly pack: FallbackContentPack;
  private readonly floors: ReadonlyMap<number, ResolvedFallbackFloor>;
  private readonly hoard: HoardFeatureParams;

  constructor(options: FallbackFloorContentProviderOptions = {}) {
    this.hoard = options.hoard ?? DEFAULT_HOARD;

    try {
      this.pack = loadFallbackContentPack(options.root);
      this.floors = validateFloors(this.pack);
    } catch (error) {
      if (error instanceof FallbackProviderError) {
        throw error;
      }

      throw wrapProviderError("fallback_content_invalid", null, error);
    }
  }

  getFloor(depth: number, seed: string): FloorContent {
    const floor = this.floors.get(depth);
    if (floor === undefined) {
      throw new FallbackProviderError(
        "fallback_depth_unavailable",
        depth,
        `fallback floor ${depth} is not available`,
        null,
      );
    }

    return {
      params: {
        ...floor.params,
        seed,
        ...(depth === config.runStructure.depthFloors
          ? { hoard: this.hoard }
          : {}),
      },
      roster: floor.roster,
      items: floor.items,
      traps: floor.traps,
      npcs: floor.npcs,
      ...(floor.quest === null ? {} : { quest: floor.quest }),
    };
  }
}

export const createFallbackFloorContentProvider = (
  options: FallbackFloorContentProviderOptions = {},
): FallbackFloorContentProvider => new FallbackFloorContentProvider(options);

const validateFloors = (
  pack: FallbackContentPack,
): ReadonlyMap<number, ResolvedFallbackFloor> => {
  const floors = new Map<number, ResolvedFallbackFloor>();

  for (let depth = 1; depth <= config.runStructure.depthFloors; depth += 1) {
    try {
      floors.set(depth, getFallbackFloor(pack, depth));
    } catch (error) {
      throw wrapProviderError("fallback_content_invalid", depth, error);
    }
  }

  return floors;
};

const wrapProviderError = (
  code: FallbackProviderErrorCode,
  depth: number | null,
  source: unknown,
): FallbackProviderError => {
  const sourceMessage = source instanceof Error ? source.message : String(source);
  const message =
    depth === null
      ? `fallback content pack is invalid: ${sourceMessage}`
      : `fallback floor ${depth} is invalid: ${sourceMessage}`;

  return new FallbackProviderError(code, depth, message, source);
};

import { ENGINE_VERSION, PROTOCOL_VERSION } from "../../schemas/protocol.js";
