    return failCheck(
      "G1_ROSTER_BUDGET",
      `roster cost ${cost} exceeds ${manifest.band} spawn budget ${budget}`,
    );
  }

  return passCheck(
    "G1_ROSTER_BUDGET",
    `roster cost ${cost} within ${manifest.band} spawn budget ${budget}`,
  );

