  .superRefine((range, ctx) => {
    if (range.min > range.max) {
      ctx.addIssue({
        code: "custom",
        path: ["min"],
        message: "roomCountRange.min must be less than or equal to max",
      });
    }
  });

export const ManifestParamsSchema = z.strictObject({
  bandOrSize: DepthBandSchema,
